var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……스승님.","JPN":"……師匠。","ENG":"Master...","TWN":"……師父。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭔가 착각하신 모양인데 여긴 보육원이 아닙니다.","JPN":"何か勘違いされているようですが、ここは保育園ではありません。","ENG":"Just so you know, this is not an orphanage.","TWN":"是不是有什麼誤會？這裡不是幼稚園。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 어쩌자고 저런 어린애를 데리고 오신 거죠?","JPN":"いったい何のつもりであんな子どもを連れてきたんですか？","ENG":"Why did you bring the kid here?","TWN":"您把那麼小的孩子帶來這裡是想做什麼呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"워치를 가지고 있고 카운터 적성도 높아.","JPN":"ウォッチを持ち、カウンター適性も高い。","ENG":"He's got a Watch and shows promising signs of becoming a Counter.","TWN":"他有能量環，制裁者適能也很高。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"항상 회사에 인력이 부족하다고 노래를 부르지 않았나?","JPN":"いつも会社に人手が足りないと訴えていなかったか？","ENG":"You were always complaining that you needed more people, weren't you?","TWN":"你不是一天到晚在哼人力短缺之歌嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말씀드리지만 저건 <color=#ffd34c>어린애</color>입니다.","JPN":"もう一度申し上げますが、あれは<color=#ffd34c>小さな子ども</color>ですよ。","ENG":"In case you missed this little detail, he's <color=#ffd34c>a child</color>.","TWN":"請容我再次提醒您，他只是個<color=#ffd34c>孩子</color>啊！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 부족하다고 했던 인력은 작전에 투입할 수 있는 현장직이고요.","JPN":"私が足りないと言った人手は作戦に投入できる現場職です。","ENG":"The people I need are active field agents I can send on actual operations right away.","TWN":"我缺的是可以直接投入作戰的人力。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 저런 꼬마를 현장에 데리고 다닐 생각이십니까?","JPN":"まさかあんな子どもを現場に連れて行くつもりですか？","ENG":"You're not thinking of taking the kid around with you, are you?","TWN":"您該不會是想帶著那麼丁點大的孩子衝鋒陷陣吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……네가 펜릴 전대에 들어왔을 때도 그다지 나이가 많은 건 아니었는데.","JPN":"……お前がフェンリル戦隊に入った当時と、そんなに歳は変わらないぞ。","ENG":"…You weren't much older than him when you joined Fenrir Division.","TWN":"……你加入芬里爾戰隊戰隊時也沒比他大多少好嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 전 천재였으니까요.","JPN":"それは私が天才だったからです。","ENG":"Well, I was a genius.","TWN":"那是因為我是天才啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 아이가 그때 제 실력의 반만큼이라도 따라온다면 반대하지 않겠습니다.","JPN":"あの子が当時の私の半分程度の実力もあるなら反対はしません。","ENG":"If this kid's at least half as good as I was back then, I won't object.","TWN":"這個孩子的能力如果有我當初的一半，那我就立刻閉嘴。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런가요?","JPN":"どうですか？","ENG":"Is he though?","TWN":"他有嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건…… 당장은 힘들겠군.","JPN":"それは……今すぐは難しそうだな。","ENG":"That… might be difficult to achieve, for now.","TWN":"這個……我無法保證。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래도 사람이 인정이라는 게 있는데 사정을 좀 봐 주면……","JPN":"人情という言葉があるだろう、今回は大目に見てやって……","ENG":"But can't you find the heart to be more flexible?","TWN":"話雖如此，人家說情理法，用人情的角度來看……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"기준을 조금 낮춰 볼 수는 없겠나?","JPN":"基準を少し下げることはできないか？","ENG":"How about you lower your bar a little?","TWN":"就不能稍微降低標準嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님 입에서 인정이라는 말이 나오다니 참 놀랍네요.","JPN":"師匠の口から人情という言葉が出るとは、本当に驚きですね。","ENG":"I can't believe you just mentioned anything about the heart.","TWN":"我竟然會從師父口裡聽到人情這兩個字。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 왜 안대를 차게 됐나 떠올린 다음에 다시 말씀해 보시죠.","JPN":"私がなぜ眼帯をするようになったのか、思い出してからもう一度話していただけませんか？","ENG":"Let's table this discussion, until you've considered why I'm wearing this eye patch in the first place.","TWN":"在跟我談人情之前，要先回想一下我為什麼會戴眼罩嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"크흠…….","JPN":"こほん……","ENG":"Ahem…","TWN":"嗯……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"저, 저기…….","JPN":"あ……あの……","ENG":"E-excuse me…","TWN":"那個……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"저…… 밥도 조금밖에 안 먹어요. 돈도 필요 없어요.","JPN":"あの……僕はご飯も少ししか食べません。お金も必要ありません。","ENG":"I… don't eat much food. And I don't need money.","TWN":"我……我吃不多，也不需要零用錢，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"시키는 대로…… 열심히 일할 테니까……","JPN":"言われたとおりに……一生懸命働くから……","ENG":"I'll work hard… do everything you say…","TWN":"只要是交代的事……我都會認真去做……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"여기 있게 해 주시면…… 안 될까요?","JPN":"ここに居させてもらうのは……ダメですか？","ENG":"So could you please… let me stay?","TWN":"可以讓我……留在這裡嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님, 애가 저렇게까지 말하는데 받아 줘도 되지 않을까요?","JPN":"社長、小さい子どもがあんなことまで言っていますし、受け入れてもいいんじゃないでしょうか？","ENG":"Boss, maybe we should let him stay. Don't you feel bad for the kid?","TWN":"老闆，孩子都已經說成這樣了，我們不能收留他嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"작전 투입은 어려워도 카운터 능력자라면 관리국에서 지원금도 나올 텐데…….","JPN":"作戦投入は難しくても、カウンター能力者なら管理局から補助金も出るはず……","ENG":"If he's a Counter, we could get extra funding from the Administration, even if we don't send him into combat.","TWN":"就算無法投入作戰，但如果他是有能力的制裁者，管理局應該會發補助吧……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"입사하자마자 잘리기 싫으면 애 데리고 나가 있으세요, 하나 씨.","JPN":"入社したてでクビになりたくなければ、その子を連れて出てください、ナカシマさん。","ENG":"Take the kid and wait outside if you want to keep this job, Hana.","TWN":"荷娜，如果你不想剛進公司就被裁員，現在就先把那孩子帶出去。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"죄, 죄송합니다! 사장님!","JPN":"す、すみません！　社長！","ENG":"S-sorry! Boss!","TWN":"老闆，對…對不起！！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"시윤이라고 했지? 누나랑 같이 간식 먹으러 가자.","JPN":"アキヤマ君だったよね？　お姉ちゃんと一緒におやつを食べにいこうか。","ENG":"You're Shiyoon, right? Let's go grab a snack together.","TWN":"你叫時雲對嗎？和姊姊一起去吃點心吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"……네.","JPN":"……はい。","ENG":"…Okay.","TWN":"……好。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님, 구 관리국은 비밀조직이었고 그때는 카운터의 수도 훨씬 적었습니다.","JPN":"師匠、旧管理局は秘密組織で、あの時はカウンターの数もごく少数でした。","ENG":"Master, the Old Administration was a clandestine organization, and there were a lot fewer Counters back then.","TWN":"師父，舊管理局是秘密組織，當時制裁者的數量也相當稀少。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"단 한 명의 카운터라도 무조건 확보해야 하는 상황이었죠.","JPN":"たった1人のカウンターでも無条件に確保しなければならない状況でした。","ENG":"We needed as many Counters as we could find.","TWN":"所以當時只要是制裁者就絕不能放過。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금은 관리국의 존재가 공공연하게 알려진 세상이고 카운터의 수도 이전보다는 많은 편입니다.","JPN":"今は管理局の存在が表に出ている上、カウンターの数も以前より増えました。","ENG":"But now, everyone knows the Administration exists. And there're plenty of Counters to go around, relatively.","TWN":"但現在管理局是公開透明的，制裁者的數量也比以前多很多。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리 회사가 가진 비밀을 생각해 보면 굳이 저런 꼬마를 키우면서까지 데리고 있어야 할 필요가 없어요.","JPN":"うちの会社が持つ秘密を考慮すれば、\\nわざわざあんな子どもを育ててまで組織に置く必要はありません。","ENG":"Given the secrecy of our company, there's no need for us to raise the boy ourselves.","TWN":"再想想我們公司的秘密，有需要把那孩子帶在身邊嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저도 알고 있는 사실을 모르진 않으실 텐데, 대체 저 꼬마는 누구죠? ","JPN":"私も知っている事実を師匠が知らないわけないと思いますが、一体あの子は誰ですか？","ENG":"But I'm sure you already know what I do. Who is this kid anyway? ","TWN":"我相信師父也很清楚情況，那個小鬼到底是誰？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정말 숨겨 뒀던 자식이라도 되는 겁니까?","JPN":"本当に隠し子でもいたのですか？","ENG":"Is he your secret son or something?","TWN":"難道是您的私生子嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……돌봐 주기로 약속했다.","JPN":"……面倒をみてやると約束した。","ENG":"…I gave my word I'd take care of him.","TWN":"……我答應要照顧他。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"언제부터 스승님이 약속을 그렇게 잘 지켰다고 그러십니까?","JPN":"いつから師匠がそんなに約束を守るようになったのですか？","ENG":"Since when do you keep your promises?","TWN":"師父您是從什麼時候開始那麼重視承諾的？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니면 대가로 돈이라도 거하게 받으신 건가요?","JPN":"それとも、対価として大金でも受け取ったんですか？","ENG":"Or did you get paid a pile of money?","TWN":"還是對方有給您鉅款？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……돈 대신 목숨을 받았어.","JPN":"……お金の代わりに命をもらった。","ENG":"…It wasn't money I took… but lives.","TWN":"……他不是給我錢，是把他的命給我。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"저 아이의 부모를 내 손으로 죽였으니까.","JPN":"あの子の親をこの手で殺したから。","ENG":"I killed the child's parents myself.","TWN":"那孩子的父母死在我手中。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"클리포트 인자 사냥이군요. 상대는 누구였죠?","JPN":"クリフォト・ファクター狩りですか。相手は誰でしたか？","ENG":"So you were out hunting Qliphoth Factor holders. Who were the targets?","TWN":"原來是因為卡巴拉因子。對方是誰？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……네 선배쯤 되는 녀석이었지.","JPN":"……お前の先輩に当たるやつだ。","ENG":"…Let's just say they were my apprentices before your time.","TWN":"……他們可以算是你的前輩。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"날 믿었던 걸 보면 너만큼 바보였던 것 같기도 했고.","JPN":"私を信じていたことを考えると、お前ぐらいバカだったような気もするな。","ENG":"They must have been as stupid as you, since they trusted me.","TWN":"他們竟然會相信我，看來跟你一樣傻呢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"미안하지만 더 자세히는 말해줄 수 없다.","JPN":"悪いが、これ以上詳しくは言えない。","ENG":"Sorry, but that's all I can tell you.","TWN":"抱歉，我只能透露這麼多。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래도 공짜로 부탁할 생각은 없어.","JPN":"しかしタダで頼むつもりはない。","ENG":"In any case, I'm not asking you to do this for free.","TWN":"但我不會讓你吃虧的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정식 태스크포스로 승인 받으려면 실적이 필요하다고 했지. 다음부터는 제대로 작전에 나가마.","JPN":"正式にタスクフォースカンパニーとして\\n承認を受けるためには実績が必要と言ったな。\\n次からまともに作戦に出てやる。","ENG":"You mentioned that the company needs a track record to be certified as an official TASKFORCE. I'll participate more properly in the missions from now on.","TWN":"你說過要得到正式特遣勢力的認可需要實績對吧？之後我會認真作戰的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"Ugh…","TWN":"哈……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 4종 침식체급 작전으로 물색해 보죠.","JPN":"わかりました。第4種侵食体作戦で探してみます。","ENG":"Very well. I'll try to find something with at least a Category 4.","TWN":"好吧，我來找找有沒有4類侵蝕體的作戰任務。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정식 태스크포스로 승인 받으려면 어지간한 실적으론 불가능할 테니까요.","JPN":"タスクフォースカンパニーとして正式に承認を得るには、中途半端な実績じゃ不可能ですからね。","ENG":"We'll need something more stellar to be certified as an official TASKFORCE.","TWN":"實績不夠好的話怎麼可能得到正式特遣勢力的認可呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……말 꺼내자마자 너무 부려먹는 거 아니냐?","JPN":"……言ったばかりでなんだが、しっかりこき使おうとしているな。","ENG":"You've just been waiting to boss me around, haven't you?","TWN":"……我話才剛說完你就等不及要弄我嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금까지 스승님이 축낸 밥값을 하려면 이 정도로는 어림도 없습니다.","JPN":"今まで師匠が無駄にした食事代を考えると、この程度では到底足りませんよ。","ENG":"This is nothing compared to how long you've been mooching off of me.","TWN":"這點程度還不夠抵師父在我這的伙食費呢！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제부턴 밥값이 2인분이 되겠군요.","JPN":"これからは食事代が2人分になりますね。","ENG":"And now we've got two moochers.","TWN":"而且現在還要多一個人吃飯，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 불평 늘어놓을 시간에 열심히 일할 생각이나 하시는 편이 좋을 겁니다.","JPN":"ですので文句を言う余裕があるなら、一生懸命働いてください。","ENG":"So you'd better get ready to work your butt off instead of complaining.","TWN":"與其抱怨，您還是認真工作賺錢吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하아…… 알았다, 알았어.","JPN":"はあ……わかった、やってやる。","ENG":"Ugh… Fine, fine.","TWN":"哈……好，我知道了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"저기…… 다른 사람들 얘기를 엿듣는 건 나쁜 일 아닌가요?","JPN":"あの……他の人の話を盗み聞きするのは悪いことではないでしょうか？","ENG":"Um… Isn't it bad to eavesdrop on other people's conversations?","TWN":"姊姊……偷聽別人講話不太好吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"으, 응?!","JPN":"う、うん！？","ENG":"H-huh?!","TWN":"嗯？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그렇긴 한데…… 어른은 가끔 나쁜 일도 해야 할 때가 있거든.","JPN":"その、そうなんだけど……大人はたまに悪いことをしなければならない時もあるの。","ENG":"Y-yeah, I guess… but sometimes grownups have to do bad things.","TWN":"欸……是不太好，但大人有時候是有苦衷的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"그런가요……?","JPN":"そうなんですか……？","ENG":"Really…?","TWN":"是這樣喔……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼. 어쨌든 사장님께서 마음을 바꾸신 것 같아 다행이야.","JPN":"そうよ。とりあえず社長が気が変わったみたいでよかった。","ENG":"Of course. Anyway, I'm glad the boss changed her mind.","TWN":"總之老闆好像改變心意了，真是太好了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아 참, 넌 무슨 말인지 모르겠구나.","JPN":"ああ、君にはどういう意味かわからないよね。","ENG":"Oh, I guess you don't know what it's about.","TWN":"對吼？你不知道我再說什麼吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 안에서 무슨 대화가 오갔냐면……","JPN":"中で何の会話がされたかというと……","ENG":"They were discussing…","TWN":"就是呢，他們剛剛在裡面說……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"저도 다 들었어요. 귀가 좋은 편이라서요.","JPN":"僕も聞きました。耳はいい方なので。","ENG":"I heard it all. I've got good hearing.","TWN":"我也都聽到了，我的聽力滿好的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그래? 대단하네?","JPN":"そ、そうなの？　すごいね！","ENG":"R-really? That's pretty impressive.","TWN":"是喔？好棒棒。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 혹시나 해서 말해 두는 건데……. 이 누나 말은 엿들으면 안 돼?","JPN":"えっと、念のために言っておくと……このお姉ちゃんの話をこっそり聞くのはダメだからね？","ENG":"Ahem… I know this isn't necessary, but just in case… Can you promise you won't eavesdrop on me?","TWN":"咳咳，先說好，你不能偷聽姐姐說話喔！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"……왜요?","JPN":"……どうしてですか？","ENG":"…Why?","TWN":"……為什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"다, 당연한 거잖아. 상대방의 프라이버시를 존중해 줘야지.","JPN":"あ、当たり前でしょう。相手のプライバシーは尊重しないとね。","ENG":"B-because you shouldn't? I mean, you should respect people's privacy.","TWN":"哪有什麼為什麼？要尊重別人的隱私呀！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"하지만 그냥 들려 버리는 걸요. 제 탓이 아니에요.","JPN":"でも、何もしなくても聞こえてしまうんです。僕のせいではありません。","ENG":"But I can hear it, even if I don't try. I can't help it.","TWN":"可是我又不是故意要偷聽的，聽力好又不是我的錯。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그러면…… 최소한 모르는 척이라도 해야 돼.","JPN":"そ、それじゃあ……知らないふりでもしておかないといけないの。","ENG":"I-in that case… At least pretend you didn't hear it.","TWN":"這樣……那你至少要裝作不知道，這樣可以嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"왜요……?","JPN":"なぜですか……？","ENG":"Why…?","TWN":"為什麼……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그게…… 원래 사람은 알고도 모르는 척, 자기 감정을 숨길 수 있어야 하는 법이야!","JPN":"え、えっと……元々人は知っていても知らないふり、自分の感情は隠さないといけないものなの！","ENG":"B-because… Sometimes people need to pretend they don't know and hide their feelings!","TWN":"因為……人必須學習隱藏自己的情緒，就算知道也要裝作不知道！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"감정을 숨긴다……","JPN":"感情を隠す……","ENG":"Hide your feelings…?","TWN":"隱藏情緒……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"저기, 그러면 좀 더 빨리 어른이 될 수 있을까요?","JPN":"あの、そうすればもっと早く大人になれるでしょうか？","ENG":"Do you think that will help me become a grownup more quickly?","TWN":"這樣就可以快點變成大人嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어어? 아마…… 그렇겠지?","JPN":"え？　多分……そうかな？","ENG":"Huh? I… guess?","TWN":"欸？可能……可以吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"그럼…… 저 노력해 볼게요.","JPN":"じゃあ……僕、頑張ってみます。","ENG":"Then… I'll give it a try.","TWN":"嗯……那我會努力的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"어른이 되면…… 저도 더 강해질 수 있을 테니까요.","JPN":"大人になれば……僕ももっと強くなれるはずだから。","ENG":"Because when I'm all grown up… I'll be stronger.","TWN":"只要變成大人……我就可以變得更強大吧？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래. 잘은 모르겠지만 웃으니까 보기 좋네.","JPN":"そうね。よくわからないけど、いい笑顔だね。","ENG":"Sure. I don't really get what you're saying, but it's good to see you smile.","TWN":"嗯，應該是吧？你笑起來很好看喔～"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아 참. 오늘부터는 너도 회사 사람이니까 김하나 대리님이라고 부르면 돼.","JPN":"ああそうだ、今日からあなたもこの会社の社員だし、私のことはナカシマ主任と呼んでね。","ENG":"Oh, right. Since you're part of the company now, you can call me Assistant Manager Kim.","TWN":"對了，從今天開始你就算是公司的一員，你叫就我金荷娜代理吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"입사 기념으로 이 대리님이 맛있는 거 사 줄게. 뭐 먹고 싶어?","JPN":"入社記念に私がおいしいものを奢ってあげる。何か食べたいものはある？","ENG":"Let me treat you to something nice to congratulate you. Is there anything you'd like?","TWN":"慶祝你第一天上班，代理買好吃的給你！你想吃什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_YOUNG_NULL","text":{"KOREA":"……바나나 우유요.","JPN":"……バナナジュース。","ENG":"…Banana milk?","TWN":"……巧克力牛奶。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"잘됐네! 나도 그거 엄청 좋아하거든!","JPN":"いいね！　私も大好きなの！","ENG":"Great! I love that stuff too!","TWN":"非常好！我也超愛巧克力牛奶的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};